/**
 * ACP Protocol Trace — 記錄所有 JSON-RPC send/recv 到 JSONL 檔案。
 * 用途：debug ACP 協議問題、回放 session 互動、效能分析。
 *
 * 每個 session 寫一個 `acp-trace-<sessionShort>.jsonl`，
 * 存放於 ${MEMORY_DIR}/acp-trace/。
 *
 * 設計決策：
 * - 因為 ACP trace 是底層協議層記錄（跟 event-log 的高層事件互補）所以獨立模組
 * - 寫入是 fire-and-forget，trace 失敗不影響主流程
 * - 記憶體 buffer（最近 200 條）供即時查詢
 */
import { appendFileSync, mkdirSync } from "node:fs";
import path from "node:path";

const MEMORY_DIR = process.env.MEMORY_DIR || "F:\\AI\\AIMemory";
const TRACE_DIR = path.join(MEMORY_DIR, "acp-trace");
const MAX_RECENT = 200;

export interface TraceEntry {
  ts: number;
  dir: "send" | "recv";
  session: string;
  data: unknown;
}

export class AcpTracer {
  private file: string;
  private recent: TraceEntry[] = [];
  private session: string;

  constructor(sessionId: string) {
    this.session = sessionId;
    const short = sessionId.slice(0, 8) || "unknown";
    mkdirSync(TRACE_DIR, { recursive: true });
    this.file = path.join(TRACE_DIR, `acp-trace-${short}.jsonl`);
  }

  /** 記錄一條發出的 JSON-RPC message。 */
  logSend(data: unknown): void {
    this._write("send", data);
  }

  /** 記錄一條收到的 JSON-RPC message。 */
  logRecv(data: unknown): void {
    this._write("recv", data);
  }

  /** 讀取最近 N 條 trace（從記憶體 buffer）。 */
  readLast(n = 50): TraceEntry[] {
    return this.recent.slice(-n);
  }

  /** Trace 檔案路徑。 */
  get filePath(): string {
    return this.file;
  }

  private _write(dir: "send" | "recv", data: unknown): void {
    const entry: TraceEntry = {
      ts: Date.now(),
      dir,
      session: this.session,
      data,
    };
    // 記憶體 buffer
    this.recent.push(entry);
    if (this.recent.length > MAX_RECENT) {
      this.recent.shift();
    }
    // 磁碟寫入（fire-and-forget，失敗不拋）
    try {
      appendFileSync(this.file, JSON.stringify(entry) + "\n", "utf8");
    } catch {
      // trace 失敗不影響主流程
    }
  }
}

/**
 * Reply Dedup — 防止 specialist/parallel delegate 結果重複注入主 session。
 *
 * 機制：對每個 (chatId, summaryHash) 做 5 分鐘時間窗去重。
 * 如果同一個 chatId 在 5 分鐘內收到相同 summary hash 的結果，
 * 視為重複並跳過注入。
 *
 * 觸發場景：
 * - retry 邏輯導致 specialist 重跑同一任務
 * - goal continuation 過程中重複觸發 delegate
 * - 網路/timeout retry 導致結果雙重回傳
 */
import { createHash } from "node:crypto";

const DEDUP_WINDOW_MS = 5 * 60 * 1000; // 5 分鐘

interface DedupEntry {
  hash: string;
  timestamp: number;
}

// chatId → 最近的 dedup entries
const _cache = new Map<number, DedupEntry[]>();

/**
 * 計算文字的去重 hash（取前 2000 字做 SHA-256 前 16 hex）。
 * 用前 2000 字是因為 specialist summary 最長就 2000。
 */
function computeHash(text: string): string {
  const input = text.slice(0, 2000);
  return createHash("sha256").update(input, "utf8").digest("hex").slice(0, 16);
}

/**
 * 檢查是否重複。若不重複則登記並回傳 false；若重複回傳 true。
 *
 * @param chatId — Telegram chat ID
 * @param summary — specialist result summary 文字
 * @returns true = 重複（應跳過注入）, false = 新的（可以注入）
 */
export function isDuplicateResult(chatId: number, summary: string): boolean {
  const now = Date.now();
  const hash = computeHash(summary);

  // 取出或初始化 cache
  let entries = _cache.get(chatId);
  if (!entries) {
    entries = [];
    _cache.set(chatId, entries);
  }

  // 清理過期 entries
  const cutoff = now - DEDUP_WINDOW_MS;
  const fresh = entries.filter((e) => e.timestamp > cutoff);

  // 檢查是否有相同 hash
  const dup = fresh.some((e) => e.hash === hash);
  if (dup) {
    _cache.set(chatId, fresh);
    return true; // 重複
  }

  // 登記新 entry
  fresh.push({ hash, timestamp: now });
  _cache.set(chatId, fresh);
  return false; // 不重複
}

/**
 * 清除指定 chatId 的 dedup cache（例如 /reset 時）。
 */
export function clearDedupCache(chatId?: number): void {
  if (chatId !== undefined) {
    _cache.delete(chatId);
  } else {
    _cache.clear();
  }
}

private async sweepIdle() {
  const now = Date.now();
  for (const [chatId, s] of this.sessions) {
    // --- Runtime Health Monitor ---
    // Detect subprocess that silently died (pid no longer valid) but
    // exit event hasn't fired yet (possible on Windows when parent shell
    // exits but Node doesn't see the signal).
    const clientPid = "pid" in s.client ? (s.client as { pid?: number }).pid : undefined;
    if (!s.client.isClosed && clientPid !== undefined) {
      try {
        // process.kill(pid, 0) throws if pid doesn't exist — non-destructive probe
        process.kill(clientPid, 0);
      } catch {
        // Process is gone but client didn't fire exit event
        console.error(`[health] chat ${chatId}: ACP subprocess (pid=${clientPid}) is dead, forcing cleanup`);
        logEvent("session_end", { reason: "health_monitor_dead_process" }, { chatId, userId: s.userId });
        this.sessions.delete(chatId);
        s.client.close().catch(() => {});
        if (this.onUnexpectedExit) {
          this.onUnexpectedExit(s, null).catch((e) =>
            console.error(`[health ${chatId}] onUnexpectedExit failed:`, e),
          );
        }
        continue; // skip idle check for this session
      }
    }

    // --- Idle timeout sweep ---
    if (now - s.lastUsed > config.sessionIdleMs) {
      console.log(`[session] dropping idle chat ${chatId}`);
      this.sessions.delete(chatId);
      if (this.onBeforeClose) {
        try { await this.onBeforeClose(s); } catch (e) {
          console.error(`[session ${chatId}] onBeforeClose failed:`, e);
        }
      }
      s.client.close().catch(() => {});
    }
  }
}

async shutdown() {
  clearInterval(this.sweeper);
  const all = Array.from(this.sessions.values());
  this.sessions.clear();
  console.log(`[session] shutdown: flushing ${all.length} session(s)`);
  if (this.onBeforeClose) {
    for (const s of all) {
      if (s.client.isClosed) {

