import { readFile, unlink } from "node:fs/promises";
import path from "node:path";
import { config } from "./config.js";
import { loadFacts, buildPreambleWithBreakdown, buildLocalPreamble } from "./memory.js";
import { formatActiveRelayTasksForPreamble } from "./working-state.js";
import { petState } from "./pet-server.js";
import { AcpProvider, DirectProvider, resolveBaseUrl, type Provider, type ProviderType, type SessionUpdate } from "./provider/index.js";
import { logEvent } from "./event-log.js";
import { recordSeqObservation, appendToolName, TURN_MARKER } from "./tool-observer.js";

const CODE_PLACEHOLDER_RE = /\u0000CODE(\d+)\u0000/g;
const RELAY_DELEGATE_RE = /<<RELAY_DELEGATE:\s*([^|>\r\n]+?)\s*\|\s*([^>\r\n]+?)\s*>>/g;

function maskCodeRegionsForRelayCapture(text: string): { masked: string; restore: (s: string) => string } {
  const slots: string[] = [];
  const masked = text.replace(/```[\s\S]*?```|`[^`\n]*`/g, (m) => {
    const idx = slots.length;
    slots.push(m);
    return `\u0000CODE${idx}\u0000`;
  });
  const restore = (s: string) =>
    s.replace(CODE_PLACEHOLDER_RE, (_m, i: string) => slots[Number(i)] ?? "");
  return { masked, restore };
}

export function isRelayDelegatePlaceholderGoal(goal: string): boolean {
  const g = goal.trim();
  return g === "" || g === "..." || g === "…" || /^<[^>\r\n]*>?$/.test(g);
}

export function captureRelayDelegateTokensFromText(buffer: string, existing: string[] = []): string[] {
  const next = [...existing];
  const { masked, restore } = maskCodeRegionsForRelayCapture(buffer);
  let m: RegExpExecArray | null;
  RELAY_DELEGATE_RE.lastIndex = 0;
  while ((m = RELAY_DELEGATE_RE.exec(masked)) !== null) {
    const goal = m[2]?.trim() ?? "";
    if (isRelayDelegatePlaceholderGoal(goal)) continue;
    const token = restore(m[0]);
    if (!next.includes(token)) next.push(token);
  }
  return next;
}

export interface HistoryEntry {
  role: "user" | "assistant";
  text: string;
  timestamp: number;
}

/**
 * Per-Telegram-chat session. Each chat owns its own Kiro ACP subprocess,
 * so conversations stay isolated.
 */
export interface ChatSession {
  chatId: number;
  userId?: number;
  client: Provider;
  /** Which provider type is active for this session. */
  activeProvider: ProviderType;
  sessionId: string;
  lastUsed: number;
  /** Accumulated assistant text for the in-flight turn. */
  buffer: string;
  /** Accumulated thinking text for the in-flight turn (local model only). */
  thinkingBuffer?: string;
  /** Human-readable tool/status lines for the in-flight turn. */
  toolLog: string[];
  /** Rolling buffer of the agent's latest stderr output. */
  stderrTail: string;
  /** Called whenever new streamed text is appended. */
  onUpdate?: (session: ChatSession) => void;
  /** Conversation history for /save export. */
  history: HistoryEntry[];
  /** Cumulative characters sent by user (approximate context-in). */
  charsIn: number;
  /** Cumulative characters emitted by agent (approximate context-out). */
  charsOut: number;
  /** Latest usage meta reported by agent (tokens, etc.), if any. */
  usage?: Record<string, unknown>;

