  inflight: boolean;
  /** Internal: inactivity timer handle for the current turn. */
  _inactivityTimer?: NodeJS.Timeout;
  /** Internal: true while a tool_call has started but not yet completed/failed. */
  _toolInFlight?: boolean;
  /** Internal: RELAY_DELEGATE tokens captured during streaming (workaround for CLI stripping tokens from final text). */
  _streamingDelegates?: string[];
  /** Path of the most recent user upload in this turn (consumed by RELAY_DELEGATE auto-attach). */
  _lastUploadPath?: string;
  /** Internal: meta prompts queued while session was inflight (e.g. parallel delegate results). Drained after inflight=false. */
  _pendingMetaQueue: Array<{ ctx: unknown; prompt: string; opts: Record<string, unknown> }>;
  /** Internal: consecutive tool call failures for reflexion hint injection. */
  _consecutiveToolFails: number;
  /** Internal: maps toolCallId → human-readable tool title (from the tool_call start event), so tool_call_update can log the real name instead of the opaque id. */
  _toolTitles?: Map<string, string>;
  /** Internal: true once the 70% context budget warning has been injected this session. */
  _budgetWarned?: boolean;
  /** Internal: set true when cancel() fires; run-prompt finally skips post-processing. */
  _cancelledTurn?: boolean;
  /** Internal: message_id of the current turn's placeholder (for cancel UI feedback). */
  _placeholderMsgId?: number;
  /**
