async function readRelayTaskLedger(): Promise<RelayTaskRecord[]> {
  try {
    const raw = await readFile(relayTaskLedgerPath(), "utf8");
    const parsed = JSON.parse(raw) as RelayTaskRecord[];
    if (!Array.isArray(parsed)) return [];
    return parsed.filter((record) =>
      record &&
      typeof record.id === "string" &&
      typeof record.peer === "string" &&
      typeof record.goal === "string"
    ).map((record) => ({
      ...record,
      status: record.status ?? "active",
      attachmentPaths: Array.isArray(record.attachmentPaths) ? record.attachmentPaths : [],
      inputPaths: Array.isArray(record.inputPaths) ? record.inputPaths : [],
      outputPaths: Array.isArray(record.outputPaths) ? record.outputPaths : [],
    }));
  } catch {
    return [];
  }
}

async function writeRelayTaskLedger(records: RelayTaskRecord[]): Promise<void> {
  await writeFile(relayTaskLedgerPath(), JSON.stringify(records, null, 2), "utf8");
}

function appendUnique(items: string[], item?: string): string[] {
  if (!item) return items;
  return items.includes(item) ? items : [...items, item];
}

export async function upsertRelayTask(update: {
  id: string;
  peer: string;
  direction: RelayTaskDirection;
  goal?: string;
  context?: string;
  status?: RelayTaskStatus;
  ownerChatId?: number;
  relayChatId?: number;
  attachmentPath?: string;
  inputPath?: string;
  outputPath?: string;
  resultSummary?: string;
}): Promise<RelayTaskRecord> {
  const now = new Date().toISOString();
  const records = await readRelayTaskLedger();
  let record = records.find((item) => item.id === update.id);
  if (!record) {
    record = {
      id: update.id,
      peer: update.peer,
      direction: update.direction,
      status: update.status ?? "active",
      goal: update.goal ?? "(relay task)",
      context: update.context,
      createdAt: now,
      updatedAt: now,
      ownerChatId: update.ownerChatId,
      relayChatId: update.relayChatId,
      attachmentPaths: [],
      inputPaths: [],
      outputPaths: [],
    };
    records.push(record);
  }

  record.peer = update.peer || record.peer;
  record.direction = update.direction || record.direction;
  if (update.goal) record.goal = update.goal;
  if (update.context) record.context = update.context;
  if (update.status) record.status = update.status;
  if (update.ownerChatId) record.ownerChatId = update.ownerChatId;
  if (update.relayChatId) record.relayChatId = update.relayChatId;
  if (update.resultSummary) record.resultSummary = update.resultSummary;
  record.attachmentPaths = appendUnique(record.attachmentPaths, update.attachmentPath);
  record.inputPaths = appendUnique(record.inputPaths, update.inputPath);
  record.outputPaths = appendUnique(record.outputPaths, update.outputPath);
  record.updatedAt = now;

  await writeRelayTaskLedger(records);
  return record;
}

export async function addRelayTaskInput(peer: string, inputPath: string): Promise<RelayTaskRecord | null> {
  const records = await readRelayTaskLedger();
  const record = records
    .filter((item) => item.peer === peer && item.status === "active")
    .sort((a, b) => b.updatedAt.localeCompare(a.updatedAt))[0];
  if (!record) return null;
  record.inputPaths = appendUnique(record.inputPaths, inputPath);
  record.updatedAt = new Date().toISOString();
  await writeRelayTaskLedger(records);
  return record;
}

export async function addRelayTaskOutput(peer: string, outputPath: string): Promise<RelayTaskRecord | null> {
  const records = await readRelayTaskLedger();
  const record = records
    .filter((item) => item.peer === peer && item.status === "active")
    .sort((a, b) => b.updatedAt.localeCompare(a.updatedAt))[0];
  if (!record) return null;
  record.outputPaths = appendUnique(record.outputPaths, outputPath);
  record.updatedAt = new Date().toISOString();
  await writeRelayTaskLedger(records);
  return record;
}

export async function formatActiveRelayTasksForPreamble(chatId: number): Promise<string> {
  const records = (await readRelayTaskLedger())
    .filter((record) =>
      record.status === "active" &&
      (record.ownerChatId === chatId || record.relayChatId === chatId)
    )
    .sort((a, b) => b.updatedAt.localeCompare(a.updatedAt))
    .slice(0, 5);

  if (records.length === 0) return "";
  const lines = records.map((record) => {
    const bits = [
      `- [${record.id}] ${record.direction} ${record.peer}: ${record.goal}`,
      record.context ? `context=${record.context.slice(0, 160)}` : "",
      record.attachmentPaths.length ? `attachments=${record.attachmentPaths.join(", ")}` : "",
      record.inputPaths.length ? `inputs=${record.inputPaths.join(", ")}` : "",
      record.outputPaths.length ? `outputs=${record.outputPaths.join(", ")}` : "",
    ].filter(Boolean);
    return bits.join(" | ");
  });
  return (
    "\n[Active relay task ledger]\n" +
    lines.join("\n") +
    "\nUse this to answer questions about in-flight bot-to-bot relay delegations across sessions.\n" +
    "[End active relay task ledger]\n\n"
  );
}

// ─── Working state persistence ────────────────────────────────────────────────

interface WriteWorkingStateDeps {
  sessions: SessionManager;
  MEMORY_DIR: string;
}

let _deps: WriteWorkingStateDeps | null = null;

export function initWorkingState(deps: WriteWorkingStateDeps): void {
  _deps = deps;
}

export async function writeWorkingState(
  chatId: number,
  reason: string,
): Promise<void> {
  const sessions = _deps?.sessions;
  const MEMORY_DIR = _deps?.MEMORY_DIR ?? config.memoryDir;
  const session = sessions?.peek(chatId);
  const gs = await goalStore.get(config.memoryDir, chatId).catch(() => null);

  const recentLines: string[] = [];
  if (session) {
    const last5 = session.history.slice(-10);
    for (const entry of last5) {
      const prefix = entry.role === "user" ? "User" : "Agent";
      const summary = entry.text.replace(/\n/g, " ").slice(0, 100);
      recentLines.push(`- ${prefix}: ${summary}`);
    }
  }

  const ws: WorkingState = {
    chatId,
    savedAt: new Date().toISOString(),
    restartReason: reason || undefined,
    task: gs?.status === "active" ? gs.objective : reason || "unknown",
    phase: gs?.status === "active" ? `turn ${gs.turns_used}/${gs.max_turns}` : "manual restart",
    completed: [],
    blocked: [],
    key_refs: [],
    next_action: reason || "resume previous work",
  };

  if (session) {
    const assistantMsgs = session.history
      .filter(e => e.role === "assistant")
      .slice(-5)
      .map(e => e.text);
    const allText = assistantMsgs.join("\n");
    for (const line of allText.split("\n")) {
      const m = line.match(/\[WS\]\s*(task|completed|blocked|key_refs|next_action):\s*(.+)/i);
      if (!m) continue;
      const [, field, value] = m;
      const v = value.trim();
      switch (field.toLowerCase()) {
        case "task": ws.task = v; break;
        case "completed": ws.completed.push(v); break;
        case "blocked": ws.blocked.push(v); break;
        case "key_refs": ws.key_refs.push(v); break;
        case "next_action": ws.next_action = v; break;
      }
    }
  }

  let md = `# Working State\n\n`;
  md += `- chatId: ${ws.chatId}\n`;
  md += `- savedAt: ${ws.savedAt}\n`;
  if (ws.restartReason) md += `- restartReason: ${ws.restartReason}\n`;
  md += `- task: ${ws.task}\n`;
  md += `- phase: ${ws.phase}\n`;
  md += `- next_action: ${ws.next_action}\n`;
  md += `\n`;

  if (ws.completed.length > 0) {
    md += `## Completed\n`;
    md += ws.completed.map(c => `- ${c}`).join("\n") + "\n\n";
  }
  if (ws.blocked.length > 0) {
    md += `## Blocked\n`;
    md += ws.blocked.map(b => `- ${b}`).join("\n") + "\n\n";
  }
  if (ws.key_refs.length > 0) {
    md += `## Key References\n`;
    md += ws.key_refs.map(r => `- ${r}`).join("\n") + "\n\n";
  }
  if (recentLines.length > 0) {
    md += `## Recent Context\n`;
    md += recentLines.slice(-5).join("\n") + "\n\n";
  }

  const filePath = path.join(MEMORY_DIR, `working-state-${chatId}.md`);
  await writeFile(filePath, md, "utf8");
  console.log(`[restart] wrote working-state for chat ${chatId}`);
}

