/**
 * Session Archive — 結構化歸檔 ACP session 狀態。
 *
 * 解決的問題：
 * - 現有 transcript 是純 markdown，無法程式化恢復上下文
 * - working-state 只有任務摘要，缺少 turn history 和 goal state
 *
 * 設計決策：
 * - 因為是單人單 session 架構所以用 per-chatId 單檔覆寫（排除 append-only 因為只需最近一次）
 * - JSON 格式方便程式化讀取（排除 markdown 因為需要結構化恢復）
 * - 歸檔與 transcript 並存：transcript 留給人讀，archive 給程式讀
 * - 恢復時只注入摘要（非完整 history），避免 context 爆炸
 */
import { writeFile, readFile, unlink } from "node:fs/promises";
import path from "node:path";
import { config } from "./config.js";
import type { ChatSession, HistoryEntry } from "./sessionManager.js";
import * as goalStore from "./goalStore.js";

// ─── Schema ───────────────────────────────────────────────────────────────────

/** 歸檔的單個 turn。比 HistoryEntry 多保留 charCount 供統計。 */
export interface ArchivedTurn {
  role: "user" | "assistant";
  /** 前 2000 字（避免歸檔過大，完整版在 transcript MD）。 */
  text: string;
  timestamp: number;
}

/** Goal 狀態快照。 */
export interface ArchivedGoal {
  objective: string;
  status: "active" | "paused" | "done" | "cleared";
  turns_used: number;
  max_turns: number;
}

/** 完整的 session 歸檔結構。 */
export interface SessionArchive {
  /** Schema 版本，方便未來 migration。 */
  version: 1;
  /** Telegram chat ID。 */
  chatId: number;
  /** Telegram user ID。 */
  userId?: number;
  /** ACP session ID。 */
  sessionId: string;
  /** Session 建立時間（ISO）。 */
  createdAt: string;
  /** 歸檔時間（ISO）。 */
  archivedAt: string;
  /** 關閉原因。 */
  closeReason: "idle" | "manual" | "reset" | "restart" | "crash" | "health_monitor";
  /** Preamble breakdown（char counts）。 */
  preambleBreakdown: {
    total: number;
    toolNotes: number;
    envBlock: number;
    memoryBlock: number;
    dailylogBlock: number;
  };
  /** Turn history（每條 text 截斷到 2000 字）。 */
  turns: ArchivedTurn[];
  /** Goal 狀態（若有）。 */
  goal?: ArchivedGoal;
  /** Session 累計統計。 */
  stats: {
    charsIn: number;
    charsOut: number;
    turnCount: number;
    durationMs: number;
  };
  /** 最近 5 條 assistant 回覆的摘要行（用於恢復時注入）。 */
  recentSummary: string[];
}

// ─── Constants ────────────────────────────────────────────────────────────────

const ARCHIVE_TEXT_LIMIT = 2000;
const RECENT_SUMMARY_COUNT = 5;
const SUMMARY_LINE_LIMIT = 150;

// ─── Export（歸檔） ───────────────────────────────────────────────────────────

/**
 * 從 ChatSession 建立歸檔結構。
 */
export async function exportSession(
  session: ChatSession,
  closeReason: SessionArchive["closeReason"],
): Promise<SessionArchive> {
  // 截斷 turn text
  const turns: ArchivedTurn[] = session.history.map((h) => ({
    role: h.role,
    text: h.text.slice(0, ARCHIVE_TEXT_LIMIT),
    timestamp: h.timestamp,
  }));

  // 取 goal state
  let goal: ArchivedGoal | undefined;
  try {
    const gs = await goalStore.get(config.memoryDir, session.chatId);
    if (gs && gs.status) {
      goal = {
        objective: gs.objective,
        status: gs.status,
        turns_used: gs.turns_used ?? 0,
        max_turns: gs.max_turns ?? 5,
      };
    }
  } catch { /* no goal — fine */ }

  // 最近 assistant 回覆摘要
  const recentSummary = session.history
    .filter((h) => h.role === "assistant")
    .slice(-RECENT_SUMMARY_COUNT)
    .map((h) => h.text.replace(/\n/g, " ").slice(0, SUMMARY_LINE_LIMIT));

  // 計算 duration
  const firstTs = session.history[0]?.timestamp ?? session.lastUsed;
  const durationMs = Date.now() - firstTs;

  const archive: SessionArchive = {
    version: 1,
    chatId: session.chatId,
    userId: session.userId,
    sessionId: session.sessionId,
    createdAt: new Date(firstTs).toISOString(),
    archivedAt: new Date().toISOString(),
    closeReason,
    preambleBreakdown: { ...session.preambleBreakdown },
    turns,
    goal,
    stats: {
      charsIn: session.charsIn,
      charsOut: session.charsOut,
      turnCount: session.history.length,
      durationMs,
    },
    recentSummary,
  };

  return archive;
}

/**
 * 將歸檔寫入磁碟。per-chatId 單檔覆寫（只保留最近一次）。
 */
export async function saveArchive(archive: SessionArchive): Promise<string> {
  const filePath = archivePath(archive.chatId);
  await writeFile(filePath, JSON.stringify(archive, null, 2), "utf8");
  console.log(`[archive] saved session archive for chat ${archive.chatId} (${archive.turns.length} turns, reason=${archive.closeReason})`);
  return filePath;
}

// ─── Import（恢復） ──────────────────────────────────────────────────────────

/**
 * 讀取上次的歸檔。回傳 null 表示沒有歸檔或讀取失敗。
 */
export async function loadArchive(chatId: number): Promise<SessionArchive | null> {
  try {
    const raw = await readFile(archivePath(chatId), "utf8");
    const parsed = JSON.parse(raw) as SessionArchive;
    // 基本 schema 驗證
    if (parsed.version !== 1 || !parsed.chatId || !Array.isArray(parsed.turns)) {
      console.warn(`[archive] invalid archive schema for chat ${chatId}, ignoring`);
      return null;
    }
    return parsed;
  } catch {
    return null; // 檔案不存在或格式錯誤
  }
}

/**
 * 從歸檔建構恢復用的 preamble block。
 * 設計：只注入摘要 + goal state + stats，不灌完整 history（避免 context 爆炸）。
 */
export function buildRestorationBlock(archive: SessionArchive): string {
  const lines: string[] = [];
  lines.push("[Previous session archive — structured context for continuity]");
  lines.push(`- sessionId: ${archive.sessionId}`);
  lines.push(`- duration: ${Math.round(archive.stats.durationMs / 60000)}min`);
  lines.push(`- turns: ${archive.stats.turnCount}`);
  lines.push(`- closed: ${archive.closeReason} at ${archive.archivedAt}`);

  if (archive.goal) {
    lines.push(`- goal: ${archive.goal.objective} (${archive.goal.status}, ${archive.goal.turns_used}/${archive.goal.max_turns} turns)`);
  }

  if (archive.recentSummary.length > 0) {
    lines.push("");
    lines.push("Recent assistant context:");
    for (const s of archive.recentSummary) {
      lines.push(`  - ${s}`);
    }
  }

  lines.push("");
  lines.push("Resume from where the previous session left off. Do not ask what was done last time.");
  lines.push("[End session archive]");

  return lines.join("\n");
}

/**
 * 刪除歸檔（恢復後可選刪除，避免下次 session 重複注入）。
 */
export async function deleteArchive(chatId: number): Promise<void> {
  try {
    await unlink(archivePath(chatId));
  } catch { /* file doesn't exist — fine */ }
}

// ─── Helpers ──────────────────────────────────────────────────────────────────

function archivePath(chatId: number): string {
  return path.join(config.memoryDir, `session-archive-${chatId}.json`);
}

