/**
 * Switch the active provider for a chat. Closes the old session and
 * creates a new one with the specified provider type.
 * Returns the new session.
 */
async switchProvider(chatId: number, type: ProviderType, userId?: number): Promise<ChatSession> {
  const existing = this.sessions.get(chatId);
  if (existing) {
    this.sessions.delete(chatId);
    await existing.client.close().catch(() => {});
  }
  return this.create(chatId, userId, type);
}

/** Start (or restart) the inactivity timer for a turn. */
startInactivityTimer(session: ChatSession) {
  this.clearInactivityTimer(session);
  const ms = session._toolInFlight && config.turnToolInactivityTimeoutMs > 0
    ? config.turnToolInactivityTimeoutMs
    : config.turnInactivityTimeoutMs;
  if (ms <= 0) return;
  session._inactivityTimer = setTimeout(() => {
    console.warn(
      `[session ${session.chatId}] turn inactivity timeout (${ms}ms, toolInFlight=${!!session._toolInFlight}) — auto-cancelling`,
    );
    session.client.cancel();
  }, ms);
  session._inactivityTimer.unref?.();
}

private resetInactivityTimer(session: ChatSession) {
  if (!session._inactivityTimer) return;
  this.startInactivityTimer(session);
}

clearInactivityTimer(session: ChatSession) {
  if (session._inactivityTimer) {
    clearTimeout(session._inactivityTimer);
    session._inactivityTimer = undefined;
  }
}

private applyUpdate(session: ChatSession, u: SessionUpdate) {
  this.resetInactivityTimer(session);
  const up = u.update;
  // Opportunistically capture usage-like meta the agent may attach.
  const meta = (up as { _meta?: Record<string, unknown> })._meta;
  const usage =
    (meta?.usage as Record<string, unknown> | undefined) ??
    ((up as { usage?: Record<string, unknown> }).usage);
  if (usage && typeof usage === "object") {
    session.usage = usage;
  }
  switch (up.sessionUpdate) {
    case "agent_message_chunk":
    case "agent_thought_chunk": {
      const content = up.content as { type?: string; text?: string } | undefined;
      if (content?.type === "text" && typeof content.text === "string") {
        const wasEmpty = session.buffer.length === 0 && !session.thinkingBuffer;

  s.client.cancel();

  // Optimistic cancel: immediately free the session so the user can send
  // new messages without waiting for the CLI to acknowledge cancellation.
  s._cancelledTurn = true;
  s.inflight = false;
  s._toolInFlight = false;
  s.onUpdate = undefined;
  this.clearInactivityTimer(s);

  // Force-kill escalation: if CLI doesn't exit the turn within 15s,
  // kill the process tree and re-create on next message.
  if (!s.client.isClosed) {
    const timer = setTimeout(async () => {
      if (s.client.isClosed) return;
      console.warn(`[cancel] chat ${chatId} CLI still alive after 15s — force-killing`);
      await s.client.close();
    }, 15_000);
    timer.unref?.();
  }
}

/** Enable drop-all mode: silently discard messages sent before now. */
enableDropAll(chatId: number) { this._dropBefore.set(chatId, Math.floor(Date.now() / 1000)); }
/** Disable drop-all mode. */
disableDropAll(chatId: number) { this._dropBefore.delete(chatId); }
/** Check if a message should be dropped (sent before the cutoff). */
shouldDrop(chatId: number, messageDate: number): boolean {
  const cutoff = this._dropBefore.get(chatId);
  if (!cutoff) return false;
  if (messageDate <= cutoff) return true;
  // Message is newer than cutoff — auto-clear and let it through
  this._dropBefore.delete(chatId);
  return false;
}

peek(chatId: number): ChatSession | undefined {
  return this.sessions.get(chatId);
}

size(): number {
  return this.sessions.size;
}

async drop(chatId: number) {
  const s = this.sessions.get(chatId);
  if (!s) return;
  this.sessions.delete(chatId);
  if (this.onBeforeClose) {
    try { await this.onBeforeClose(s); } catch (e) {

      console.error(`[session ${chatId}] onBeforeClose failed:`, e);
    }
  }
  await s.client.close();
}

private async sweepIdle() {
  const now = Date.now();
  for (const [chatId, s] of this.sessions) {
    // --- Runtime Health Monitor ---
    // Detect subprocess that silently died (pid no longer valid) but
    // exit event hasn't fired yet (possible on Windows when parent shell
    // exits but Node doesn't see the signal).
    const clientPid = "pid" in s.client ? (s.client as { pid?: number }).pid : undefined;
    if (!s.client.isClosed && clientPid !== undefined) {
      try {
        // process.kill(pid, 0) throws if pid doesn't exist — non-destructive probe
        process.kill(clientPid, 0);
      } catch {
        // Process is gone but client didn't fire exit event
        console.error(`[health] chat ${chatId}: ACP subprocess (pid=${clientPid}) is dead, forcing cleanup`);
        logEvent("session_end", { reason: "health_monitor_dead_process" }, { chatId, userId: s.userId });
        this.sessions.delete(chatId);
        s.client.close().catch(() => {});
        if (this.onUnexpectedExit) {
          this.onUnexpectedExit(s, null).catch((e) =>
            console.error(`[health ${chatId}] onUnexpectedExit failed:`, e),
          );
        }
        continue; // skip idle check for this session

export async function onBeforeClose(s: ChatSession): Promise<void> {
  const { MEMORY_DIR, RESTART_PENDING_FILE, getRestartPendingChatId } = d();

  // Save working state before closing (same as /restart).
  try {
    await writeWorkingState(s.chatId, "session closed");
  } catch (err) {
    console.error(`[session ${s.chatId}] writeWorkingState on close failed:`, err);
  }

  let transcriptPath: string | undefined;
  if (s.history.length > 0) {
    try {
      const filename = await saveTranscript(s);
      transcriptPath = path.join(MEMORY_DIR, "sessions", filename);
      console.log(`[memory] chat ${s.chatId}: saved transcript → sessions/${filename}`);
      if (getRestartPendingChatId() === s.chatId) {
        try {
          const raw = await readFile(RESTART_PENDING_FILE, "utf8");
          const marker = JSON.parse(raw) as Record<string, unknown>;
          marker.savedFilename = filename;
          marker.savedCount = s.history.length;
          await writeFile(RESTART_PENDING_FILE, JSON.stringify(marker), "utf8");
        } catch (err) {
          console.error("[restart] failed to update pending marker with save info:", err);
        }
      }
    } catch (err) {
      console.error(`[memory] chat ${s.chatId}: saveTranscript on close failed:`, (err as Error).message);
    }
  }
  try {
    const added = await withTimeout(
      extractFromSession(s),
      config.memoryExtractTimeoutMs,
      `extract(chat ${s.chatId})`,
      () => {
        try { s.client.cancel(); } catch { /* noop */ }
      },
    );
    if (added > 0) {
      console.log(`[memory] chat ${s.chatId}: extracted ${added} new fact(s) on close`);
    }
  } catch (err) {
    const reason = (err as Error).message;
    console.error(`[memory] chat ${s.chatId}: extract on close failed:`, reason);
    if (s.userId && transcriptPath) {
      await enqueuePendingExtract({
        userId: s.userId,
        chatId: s.chatId,
        transcriptPath,
        reason,
        queuedAt: new Date().toISOString(),
      });
    }
  }
}

export async function onUnexpectedExit(s: ChatSession, code: number | null): Promise<void> {
  const { bot } = d();
  const notice = `⚠️ Agent 意外退出 (code=${code})，session 已重置。下次訊息會自動建立新 session。`;
  bot.api.sendMessage(s.chatId, notice).catch(() => {});

  if (s.history.length === 0) return;
  try {
    const filename = await saveTranscript(s);
    console.log(`[memory] chat ${s.chatId}: agent exited (code=${code}); saved transcript → sessions/${filename}`);
  } catch (err) {
    console.error(`[memory] chat ${s.chatId}: saveTranscript after unexpected exit failed:`, (err as Error).message);
  }
}

