async shutdown() {
  clearInterval(this.sweeper);
  const all = Array.from(this.sessions.values());
  this.sessions.clear();
  console.log(`[session] shutdown: flushing ${all.length} session(s)`);
  if (this.onBeforeClose) {
    for (const s of all) {
      if (s.client.isClosed) {
        console.log(`[session] shutdown: skipping already-closed chat ${s.chatId}`);
        continue;
      }
      console.log(`[session] shutdown: running onBeforeClose for chat ${s.chatId} (history=${s.history.length})`);
      try { await this.onBeforeClose(s); } catch (e) {
        console.error(`[session ${s.chatId}] onBeforeClose failed:`, e);
      }
    }
  }
  await Promise.all(all.map((s) => s.client.isClosed ? Promise.resolve() : s.client.close()));
  console.log(`[session] shutdown: done`);
