/**
 * Shared dependencies injected into command handlers.
 * Avoids circular imports — index.ts calls initCommandDeps() once at startup.
 */
import type { Context } from "grammy";
import type { ChatSession } from "../sessionManager.js";
import type { ProviderType } from "../provider/types.js";
import type { ScheduleStore, ScheduleEntry } from "../schedule-store.js";
import type { Scheduler } from "../scheduler.js";

export interface CommandDeps {
  isAllowed: (ctx: Context) => boolean;
  sessions: {
    get(chatId: number, userId?: number): Promise<ChatSession>;
    peek(chatId: number): ChatSession | undefined;
    resetTurn(session: ChatSession): void;
    clearInactivityTimer(session: ChatSession): void;
    drop(chatId: number): Promise<void>;
    cancel(chatId: number): void;
    enableDropAll(chatId: number): void;
    switchProvider(chatId: number, type: ProviderType, userId?: number): Promise<ChatSession>;
    size(): number;
    shutdown(): Promise<void>;
  };
  runPrompt: (
    ctx: Context,
    session: ChatSession,
    prompt: string,
    opts?: any,
  ) => Promise<void>;
  commandHandlers: Record<string, (ctx: Context) => Promise<void>>;
  cancelPendingContinuation: (chatId: number) => void;
  formatRelative: (ms: number) => string;
  scheduleStore: ScheduleStore;
  scheduler: Scheduler;
  extractFromSession: (session: ChatSession) => Promise<number>;
  parseFactsJson: (raw: string) => string[];
  saveTranscript: (session: ChatSession) => Promise<string>;
  estimateTokens: ((text: string) => number) & ((chars: number) => number);
  buildHelpMenuKeyboard: () => any;
  buildReplyKeyboard: () => any;
  helpIntro: string;
  sendMessage?: (chatId: number, text: string) => Promise<void>;
}

let _deps: CommandDeps | null = null;

export function initCommandDeps(deps: CommandDeps): void {
  _deps = deps;
}

