/**
 * Smoke test: Session Archive (P1 improvement)
 *
 * 驗證 exportSession / saveArchive / loadArchive / buildRestorationBlock / deleteArchive
 * 的核心邏輯正確性。
 */
import { writeFileSync, mkdirSync, rmSync, existsSync, readFileSync } from "node:fs";
import path from "node:path";
import { fileURLToPath } from "node:url";

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const ROOT = path.resolve(__dirname, "..");

let passed = 0;
let failed = 0;

function assert(cond, msg) {
  if (cond) { console.log(`  ✅ ${msg}`); passed++; }
  else { console.error(`  ❌ ${msg}`); failed++; }
}

// Setup temp MEMORY_DIR
const tmpDir = path.join(ROOT, "tmp", "archive-test-" + Date.now());
mkdirSync(tmpDir, { recursive: true });
const origMemDir = process.env.MEMORY_DIR;
process.env.MEMORY_DIR = tmpDir;

// Need to also mock goalStore — write a minimal goal file
const goalDir = tmpDir;
const chatId = 12345;

// Build first then import
const distUrl = (f) => new URL("file:///" + path.join(ROOT, "dist", f).replace(/\\/g, "/")).href;

console.log("\n═══ 1. exportSession ═══");

const { exportSession, saveArchive, loadArchive, buildRestorationBlock, deleteArchive } = await import(distUrl("session-archive.js"));

// Mock a ChatSession-like object
const mockSession = {
  chatId,
  userId: 999,
  sessionId: "test-session-abc123",
  lastUsed: Date.now(),
  history: [
    { role: "user", text: "Hello, how are you?", timestamp: Date.now() - 60000 },
    { role: "assistant", text: "I'm doing well! How can I help you today? This is a longer response to test the summary truncation behavior when text exceeds the limit.", timestamp: Date.now() - 55000 },
    { role: "user", text: "Can you help me with TypeScript?", timestamp: Date.now() - 30000 },
    { role: "assistant", text: "Of course! TypeScript is great. What specific question do you have?", timestamp: Date.now() - 25000 },
  ],
  charsIn: 500,
  charsOut: 1200,
  preambleBreakdown: {
    total: 8000,
    toolNotes: 500,
    envBlock: 300,
    memoryBlock: 6000,
    dailylogBlock: 1200,
  },
};

const archive = await exportSession(mockSession, "reset");

assert(archive.version === 1, "archive.version === 1");
assert(archive.chatId === chatId, "archive.chatId matches");
assert(archive.userId === 999, "archive.userId matches");
assert(archive.sessionId === "test-session-abc123", "archive.sessionId matches");
assert(archive.closeReason === "reset", "archive.closeReason === 'reset'");
assert(archive.turns.length === 4, `archive.turns.length === 4 (got ${archive.turns.length})`);
assert(archive.stats.turnCount === 4, "archive.stats.turnCount === 4");
assert(archive.stats.charsIn === 500, "archive.stats.charsIn === 500");
assert(archive.stats.charsOut === 1200, "archive.stats.charsOut === 1200");
assert(archive.stats.durationMs > 0, "archive.stats.durationMs > 0");
assert(archive.recentSummary.length === 2, `recentSummary has 2 assistant entries (got ${archive.recentSummary.length})`);
assert(archive.preambleBreakdown.total === 8000, "preambleBreakdown.total preserved");

console.log("\n═══ 2. saveArchive + loadArchive ═══");

const filePath = await saveArchive(archive);
assert(existsSync(filePath), "archive file was written to disk");

const loaded = await loadArchive(chatId);
assert(loaded !== null, "loadArchive returns non-null");
assert(loaded.version === 1, "loaded.version === 1");
assert(loaded.chatId === chatId, "loaded.chatId matches");
assert(loaded.turns.length === 4, "loaded.turns.length === 4");
assert(loaded.closeReason === "reset", "loaded.closeReason preserved");
assert(loaded.recentSummary.length === 2, "loaded.recentSummary preserved");

console.log("\n═══ 3. buildRestorationBlock ═══");

const block = buildRestorationBlock(loaded);
assert(typeof block === "string", "buildRestorationBlock returns string");
assert(block.includes("[Previous session archive"), "block has opening tag");
assert(block.includes("[End session archive]"), "block has closing tag");
assert(block.includes("test-session-abc123"), "block contains sessionId");
assert(block.includes("reset"), "block contains closeReason");
assert(block.includes("Recent assistant context"), "block has recent summary section");
assert(block.includes("Resume from where"), "block has resume instruction");

console.log("\n═══ 4. deleteArchive ═══");

await deleteArchive(chatId);
const afterDelete = await loadArchive(chatId);
assert(afterDelete === null, "loadArchive returns null after deleteArchive");

console.log("\n═══ 5. Edge cases ═══");

// Empty history
const emptySession = { ...mockSession, history: [], charsIn: 0, charsOut: 0 };
const emptyArchive = await exportSession(emptySession, "idle");
assert(emptyArchive.turns.length === 0, "empty history produces empty turns");
assert(emptyArchive.recentSummary.length === 0, "empty history produces empty recentSummary");
assert(emptyArchive.stats.turnCount === 0, "empty stats.turnCount");

// Text truncation (>2000 chars)
const longText = "x".repeat(3000);
const longSession = {
  ...mockSession,
  history: [{ role: "user", text: longText, timestamp: Date.now() }],
};
const longArchive = await exportSession(longSession, "manual");
assert(longArchive.turns[0].text.length === 2000, "text truncated to 2000 chars");

// loadArchive with no file
const noArchive = await loadArchive(99999);
assert(noArchive === null, "loadArchive for non-existent chatId returns null");

// Cleanup
rmSync(tmpDir, { recursive: true, force: true });
process.env.MEMORY_DIR = origMemDir;

console.log(`\n═══ 結果：${passed} passed, ${failed} failed ═══`);
process.exit(failed > 0 ? 1 : 0);

